// Roteia os eventos do backend (ENGAGEMENT_WEBHOOK_URL) e monta a mensagem.
// Eventos tratados:
//   leader.points_awarded (awardedEventType=supporter.created) → avisa o líder na hora
//   leader.weekly_goal_reached → parabéns por meta semanal
//   leader.inactive_7_days → resgate de liderança inativa
const body = $input.item.json.body || {};
const type = body.eventType;
const meta = body.metadata || {};
const phone = (body.phone || '').toString().replace(/\D/g, '');
const name = body.userName || 'Líder';

let message = null;

if (type === 'leader.points_awarded' && meta.awardedEventType === 'supporter.created') {
  const who = meta.supporterName ? `*${meta.supporterName}*` : 'Um novo apoiador';
  const rank = body.rankingPosition ? ` (${body.rankingPosition}º no ranking)` : '';
  message =
    `🎉 ${name}, boa notícia! ${who} acabou de entrar na sua rede pelo seu link.\n\n` +
    `+${meta.points ?? 10} pontos para você — total: ${body.score} pts${rank}.\n\n` +
    `Continue compartilhando seu link! 💪`;
} else if (type === 'leader.weekly_goal_reached') {
  message =
    `👏 Parabéns, ${name}! Você bateu a meta semanal com ${body.weeklyIndications ?? ''} indicações. ` +
    `Seu trabalho está fortalecendo a rede — continue nesse ritmo!`;
} else if (type === 'leader.inactive_7_days') {
  message =
    `Olá, ${name}! 🙏 Sentimos sua falta na Rede Guti — já faz uma semana sem novas indicações.\n\n` +
    `Que tal compartilhar seu link de cadastro hoje? Qualquer dificuldade, fale com a coordenação. 💙`;
}

return [{
  json: {
    phone,
    message,
    skip: !message || !phone,
    eventType: type,
    userId: body.userId || null
  }
}];
